// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.AdminShadowFilter) predicate.AdminShadowFilter {
	return predicate.AdminShadowFilter(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.AdminShadowFilter) predicate.AdminShadowFilter {
	return predicate.AdminShadowFilter(sql.NotPredicates(p))
}
